function identity<T>(x: T): T { return x; }
const n = identity(1); // number
const s = identity('a'); // string

type Fetch = { kind: 'idle' } | { kind: 'ok', data: string } | { kind: 'err', error: Error };
function render(s: Fetch) {
  switch (s.kind) {
    case 'ok': return s.data;
    case 'err': return s.error.message;
    case 'idle': return '...';
  }
}

function isUser(x: unknown): x is User {
  return !!x && typeof (x as any).id === 'number';
}

type Mutable<T> = { -readonly [K in keyof T]: T[K] };
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};
interface User { name: string; age: number; }
type UserGetters = Getters<User>; // { getName: () => string; getAge: () => number; }

type NonNullableX<T> = T extends null | undefined ? never : T;
type A = NonNullableX<string | null>; // string

// Disable distribution:
type IsUnion<T, U = T> = [T] extends [U] ? false : true;

type ReturnTypeX<F> = F extends (...args: any[]) => infer R ? R : never;
type ElementType<T> = T extends (infer E)[] ? E : T;

type R = ReturnTypeX<() => number>; // number
type E = ElementType<string[]>;    // string

type Event = 'click' | 'hover';
type Handler = `on${Capitalize<Event>}`; // 'onClick' | 'onHover'

type Route = `/users/${number}`;
const r: Route = '/users/42';

const Color = { Red: 'red', Green: 'green' } as const;
type Color = typeof Color[keyof typeof Color]; // 'red' | 'green'

// vs
enum ColorEnum { Red = 'red', Green = 'green' }

type Config = Record<string, number | string>;
const config = {
  port: 3000,
  host: 'localhost'
} satisfies Config;

config.port.toFixed(); // ✅ port is still number, not number | string

function parse(x: string): string[];
function parse(x: number): number[];
function parse(x: string | number): string[] | number[] {
  return typeof x === 'string' ? x.split('') : [x];
}
const a = parse('ab'); // string[]
const b = parse(5);    // number[]

